const cors = require('cors');
const LockManager = require('node-locksmith');
const createLogger = require('../../services/Logger');
const configurations = require('./config.json');

// Create the application
const app = express();
const logger = createLogger('porting-server'); // Attach logger to the app
const lockManager = new LockManager({
    lockFileName: 'porting-server.lock',
    // Additional LockManager configurations...
});

/**
 * Attach termination handlers to provide graceful exit behavior.
 */
lockManager.initializeTerminationHandlers();

/**
 * Sets up middleware for the Express app.
 */
function setupMiddleware() {
    app.use(cors());
    app.use(methodOverride('X-HTTP-Method-Override'));
    app.use(bodyParser.json({ limit: '10mb' }));
    app.use(bodyParser.urlencoded({ limit: '10mb', extended: true, parameterLimit: 10000 }));
    // Add any additional middleware...
}

/**
 * Handles CORS pre-flight requests and logging for incoming requests.
 */
function configureCorsAndLogging() {
    app.use((req, res, next) => {
        logger.info('Processing request:', req.url);
        if (req.body && Object.keys(req.body).length > 0) {
            logger.info('Request Body:', req.body);
        }
        res.header('Access-Control-Allow-Origin', '*');
        res.header('Access-Control-Allow-Headers', 'Content-Type, Authorization');
        res.header('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE, PATCH');
        if (req.method === 'OPTIONS') {
            return res.status(200).json({});
        } else {
            next();
        }
    });
}

/**
 * Creates error handling middleware.
 */
function setupErrorHandling() {
    app.use((err, req, res, next) => {
        if (err.name === 'UnauthorizedError') {
            res.status(401).json({ message: `${err.name}: ${err.message}` });
        } else {
            logger.error(err.stack);
            res.status(500).json({ message: 'Internal Server Error' });
        }
    });
}

/**
 * Dynamically loads routes for the Express app.
 */
function createRoutes() {
    const routes = require('./routes');
    Object.entries(routes).forEach(([route, controller]) => {
        app.use(route, controller(app, route)); // Attach the controller to the specified route
    });
}

/**
 * Initializes the application server, including middleware, routes, and error handling.
 */
async function initializeApp() {
    try {
        await lockManager.checkLock();
        await lockManager.createLock(Infinity, 3);
        await connectToDatabase(configurations.mongodbURL); // Ensure this is an existing function.

        setupMiddleware();
        configureCorsAndLogging();
        createRoutes();
        setupErrorHandling();

        // Listen to unhandled promise rejections
        process.on('unhandledRejection', (error) => {
            logger.error('Unhandled Promise Rejection:', error);
        });

        const httpPort = configurations.serverPort;
        http.createServer(app).listen(httpPort, () => {
            logger.info(`HTTP server is listening on port: ${httpPort}`);
        });
    } catch (error) {
        logger.error('Initialization error:', error);
        process.exit(1);
    }
}

initializeApp(); // Initialize the app

module.exports = app; // Export the express app for testing or further extension
